import ipaddress

iocs = inputs.get('iocs', [])
intel_results = []
seen = set()

def is_public_ip(value):
    try:
        ip_obj = ipaddress.ip_address(value)
    except Exception:
        return False
    return not (
        ip_obj.is_private
        or ip_obj.is_loopback
        or ip_obj.is_reserved
        or ip_obj.is_link_local
        or ip_obj.is_multicast
        or ip_obj.is_unspecified
    )

for ioc in iocs:
    ioc_type = ioc.get('type', '')
    ioc_value = str(ioc.get('value', '')).strip()
    key = (ioc_type, ioc_value)

    if not ioc_value or key in seen:
        continue
    seen.add(key)

    if ioc_type == 'ip':
        if not is_public_ip(ioc_value):
            continue
        result = tool.run_safe('threatbook_ip_query', ip=ioc_value)
        if result['success']:
            intel_results.append({
                'source': 'threatbook',
                'type': 'ip',
                'value': ioc_value,
                'result': result['text']
            })
        vt_result = tool.run_safe('virustotal_ip_query', ip=ioc_value)
        if vt_result['success']:
            intel_results.append({
                'source': 'virustotal',
                'type': 'ip',
                'value': ioc_value,
                'result': vt_result['text']
            })

    elif ioc_type == 'domain':
        result = tool.run_safe('threatbook_domain_query', domain=ioc_value)
        if result['success']:
            intel_results.append({
                'source': 'threatbook',
                'type': 'domain',
                'value': ioc_value,
                'result': result['text']
            })
        vt_result = tool.run_safe('virustotal_domain_query', domain=ioc_value)
        if vt_result['success']:
            intel_results.append({
                'source': 'virustotal',
                'type': 'domain',
                'value': ioc_value,
                'result': vt_result['text']
            })

    elif ioc_type == 'url':
        result = tool.run_safe('threatbook_url_query', url=ioc_value)
        if result['success']:
            intel_results.append({
                'source': 'threatbook',
                'type': 'url',
                'value': ioc_value,
                'result': result['text']
            })
        vt_result = tool.run_safe('virustotal_url_query', url=ioc_value)
        if vt_result['success']:
            intel_results.append({
                'source': 'virustotal',
                'type': 'url',
                'value': ioc_value,
                'result': vt_result['text']
            })

outputs['intel_results'] = intel_results
outputs['has_intel'] = len(intel_results) > 0

import json

parsed_alert = inputs.get('parsed_alert', {})
vuln_id = parsed_alert.get('vuln_id', '')
vuln_info = {}

if vuln_id:
    result = tool.run_safe('__mcp_vuln_query', vuln_id=vuln_id)
    if result['success']:
        try:
            obj = result.get('obj')
            if isinstance(obj, str):
                obj = json.loads(obj)
            vuln_info = obj if isinstance(obj, dict) else {}
        except Exception:
            vuln_info = {'raw_result': result.get('text', '')}
    else:
        vuln_info = {'error': result.get('error', 'Query failed'), 'vuln_id': vuln_id}

outputs['vuln_info'] = vuln_info
outputs['has_vuln_info'] = bool(vuln_info) and 'error' not in vuln_info

import os
import re
import json
import datetime
from flocks.workspace.manager import WorkspaceManager

parsed_alert = inputs.get('parsed_alert', {})
payload = parsed_alert.get('payload', '')
response = parsed_alert.get('response', '')
status = parsed_alert.get('status', 0)
failed_by = parsed_alert.get('failed_by', [])
threat_result = parsed_alert.get('threat_result', '')

prompt = f"""你是一位网络安全专家，正在分析 HTTP 请求和响应来判断攻击是否成功。

请求内容:
{payload}

响应内容:
{response}

补充信号:
- HTTP 状态码: {status}
- TDP result: {threat_result}
- failed_by: {failed_by}

请严格输出 JSON，对象中必须包含以下字段：
{{
  \"is_attack\": true/false,
  \"attack_success\": true/false,
  \"summary\": \"不超过120字的中文结论\",
  \"success_evidence\": [\"字符串\"],
  \"reason\": \"简要原因\"
}}
"""

analysis_raw = llm.ask(prompt)
analysis_obj = {}
try:
    matched = re.search(r'\{.*\}', analysis_raw, re.S)
    if matched:
        analysis_obj = json.loads(matched.group(0))
except Exception:
    analysis_obj = {}

status_int = 0
try:
    status_int = int(status)
except Exception:
    status_int = 0

def fallback_success():
    if any('http_status_4' in item or 'http_status_5' in item for item in failed_by):
        return False
    if status_int >= 400:
        return False
    if threat_result in ('success', 'succeeded'):
        return True
    return False

attack_success = bool(analysis_obj.get('attack_success')) if analysis_obj else fallback_success()
summary = analysis_obj.get('summary') if analysis_obj else ''
reason = analysis_obj.get('reason') if analysis_obj else ''
success_evidence = analysis_obj.get('success_evidence') if analysis_obj else []
if not isinstance(success_evidence, list):
    success_evidence = [str(success_evidence)] if success_evidence else []

response_analysis = summary or analysis_raw
if reason:
    response_analysis += f'\n原因: {reason}'
if success_evidence:
    response_analysis += '\n成功标志: ' + '；'.join(str(item) for item in success_evidence if item)

ws = WorkspaceManager.get_instance()
output_dir = str(ws.get_workspace_dir() / 'outputs' / datetime.date.today().isoformat())
artifacts_dir = os.path.join(output_dir, 'artifacts')
os.makedirs(artifacts_dir, exist_ok=True)
tool.run('write', filePath=os.path.join(artifacts_dir, 'response_analysis_llm_output.md'), content=response_analysis)

outputs['response_analysis'] = response_analysis
outputs['has_response_analysis'] = bool(response_analysis)
outputs['attack_success'] = attack_success

import os
import json
import datetime
from flocks.workspace.manager import WorkspaceManager

parsed_alert = inputs.get('parsed_alert', {})
intel_results = inputs.get('intel_results', [])
vuln_info = inputs.get('vuln_info', {})
payload_analysis = inputs.get('payload_analysis', '')
response_analysis = inputs.get('response_analysis', '')
attack_success = inputs.get('attack_success', False)

def severity_to_text(value):
    mapping = {0: 'low', 1: 'low', 2: 'medium', 3: 'high', 4: 'critical'}
    if isinstance(value, int):
        return mapping.get(value, str(value))
    if str(value).isdigit():
        return mapping.get(int(value), str(value))
    return str(value) or 'unknown'

severity_text = severity_to_text(parsed_alert.get('severity', 'unknown'))
report_content = f"""# NDR/TDP 告警分析报告

## 执行摘要

**告警类型**: {parsed_alert.get('alert_type', 'unknown')}
**严重级别**: {severity_text}
**攻击是否成功**: {'是' if attack_success else '否'}
**URL**: {parsed_alert.get('url', 'N/A')}

### 主要发现
- 源 IP: {parsed_alert.get('src_ip', 'N/A')}
- 目的 IP: {parsed_alert.get('dst_ip', 'N/A')}
- 协议: {parsed_alert.get('protocol', 'N/A')}
- 端口: {parsed_alert.get('src_port', 'N/A')} -> {parsed_alert.get('dst_port', 'N/A')}
- TDP 判定: {parsed_alert.get('threat_result', 'N/A')}
- 失败信号: {', '.join(parsed_alert.get('failed_by', [])) or '无'}

---

## 详细分析

### 1. IOC
```json
{json.dumps(parsed_alert.get('iocs', []), ensure_ascii=False, indent=2)}
```

### 2. 威胁情报查询结果
"""

if intel_results:
    for intel in intel_results:
        report_content += f"\n**{intel['source']} - {intel['type']}**: {intel['value']}\n```\n{intel['result']}\n```\n"
else:
    report_content += '\n未查询到可用外部情报，或 IOC 仅包含内网/保留地址。\n'

report_content += '\n### 3. 漏洞信息\n'
if vuln_info:
    report_content += f"\n```json\n{json.dumps(vuln_info, ensure_ascii=False, indent=2)}\n```\n"
else:
    report_content += '\n未识别到标准漏洞编号，跳过漏洞查询。\n'

report_content += f"""
### 4. 攻击负载分析
{payload_analysis or '无'}

### 5. 响应包分析
{response_analysis or '无'}

---

## 风险评估

- **风险等级**: {'High' if attack_success else 'Medium'}
- **攻击成功**: {'是 - 建议紧急响应' if attack_success else '否 - 当前更像扫描或失败尝试'}

---

## 建议与行动项

1. {'立即阻断源 IP 通信并检查目标主机是否已落地 WebShell。' if attack_success else '结合 Web/WAF/主机日志复核该请求，确认是否仅为扫描或误报。'}
2. 检查目标主机 {parsed_alert.get('dst_ip', 'N/A')} 对应 Web 服务和目录访问日志。
3. 如 URL 涉及敏感上传/脚本路径，建议核查文件完整性与最近变更。
4. 将该源地址与其他探测、爆破、上传类告警做关联分析。

---

## 数据来源

- 威胁情报: ThreatBook, VirusTotal
- 漏洞信息: Vulnerability Database
- 分析: LLM-based analysis
"""

ws = WorkspaceManager.get_instance()
output_dir = str(ws.get_workspace_dir() / 'outputs' / datetime.date.today().isoformat())
artifacts_dir = os.path.join(output_dir, 'artifacts')
os.makedirs(artifacts_dir, exist_ok=True)
report_path = os.path.join(artifacts_dir, 'final_report.md')
tool.run('write', filePath=report_path, content=report_content)

outputs['final_report'] = report_content
outputs['report_path'] = report_path
outputs['risk_level'] = 'High' if attack_success else 'Medium'
outputs['action_required'] = '紧急响应' if attack_success else '持续监控'
outputs['action_details'] = '建议立即阻断源 IP 通信，隔离受影响系统，并进行深入调查' if attack_success else '建议记录该告警，结合 Web/WAF/主机日志持续监控并复核'
